#### 3.2 TinyUfo Cache Wrapper (`src/cache.rs`)

```rust
use bytes::Bytes;
use std::sync::Arc;
use std::time::{Duration, Instant};
use tinyufo::TinyUfo;

pub struct MediaCache {
    cache: TinyUfo<String, CacheEntry>,
    ttl: Duration,
}

struct CacheEntry {
    data: Bytes,
    content_type: String,
    inserted_at: Instant,
}

impl MediaCache {
    pub fn new(capacity_mb: usize, ttl_seconds: u64) -> Self {
        // Estimate ~10KB per segment average
        let estimated_entries = (capacity_mb * 1024) / 10;
        Self {
            cache: TinyUfo::new(estimated_entries, estimated_entries),
            ttl: Duration::from_secs(ttl_seconds),
        }
    }

    pub fn get(&self, key: &str) -> Option<(Bytes, String)> {
        self.cache.get(&key.to_string()).and_then(|entry| {
            if entry.inserted_at.elapsed() < self.ttl {
                Some((entry.data.clone(), entry.content_type.clone()))
            } else {
                None // Expired
            }
        })
    }

    pub fn insert(&self, key: String, data: Bytes, content_type: String) {
        let entry = CacheEntry {
            data,
            content_type,
            inserted_at: Instant::now(),
        };
        // Weight = 1 for simplicity (could use byte size)
        self.cache.put(key, entry, 1);
    }
}
```

#### 3.3 GCS Backend (`src/gcs.rs`)

```rust
use anyhow::Result;
use bytes::Bytes;
use google_cloud_storage::client::{Client, ClientConfig};
use google_cloud_storage::http::objects::get::GetObjectRequest;
use std::sync::Arc;

pub struct GcsBackend {
    client: Client,
    bucket: String,
    prefix: String,
}

impl GcsBackend {
    pub async fn new(bucket: String, prefix: String) -> Result<Self> {
        // Uses ADC (Application Default Credentials) in GKE
        let config = ClientConfig::default().with_auth().await?;
        let client = Client::new(config);

        Ok(Self { client, bucket, prefix })
    }

    /// Fetch object from GCS
    /// path: "content/{content_id}/playlist.m3u8" or "content/{content_id}/segment_001.ts"
    pub async fn get_object(&self, path: &str) -> Result<(Bytes, String)> {
        let full_path = format!("{}{}", self.prefix, path);

        let request = GetObjectRequest {
            bucket: self.bucket.clone(),
            object: full_path,
            ..Default::default()
        };

        let data = self.client.download_object(&request, &Default::default()).await?;

        // Determine content type from extension
        let content_type = if path.ends_with(".m3u8") {
            "application/vnd.apple.mpegurl"
        } else if path.ends_with(".ts") {
            "video/mp2t"
        } else {
            "application/octet-stream"
        };

        Ok((Bytes::from(data), content_type.to_string()))
    }
}
```

#### 3.4 JWT Auth (`src/auth.rs`)

Compatible with existing `/Users/pikeymickey/aiyou-fastapi-services/src/aiyou/auth.py`:

```rust
use jsonwebtoken::{decode, DecodingKey, Validation, Algorithm};
use serde::{Deserialize, Serialize};
use thiserror::Error;

#[derive(Debug, Serialize, Deserialize)]
pub struct Claims {
    pub sub: String,           // user_id
    pub exp: usize,            // expiration
    pub jti: String,           // token ID
    #[serde(rename = "type")]
    pub token_type: Option<String>,
}

#[derive(Error, Debug)]
pub enum AuthError {
    #[error("Missing authorization header")]
    MissingHeader,
    #[error("Invalid token format")]
    InvalidFormat,
    #[error("Token validation failed: {0}")]
    ValidationFailed(#[from] jsonwebtoken::errors::Error),
}

pub struct JwtVerifier {
    decoding_key: DecodingKey,
    validation: Validation,
}

impl JwtVerifier {
    pub fn new(secret: &str, algorithm: &str) -> Self {
        let algo = match algorithm {
            "HS256" => Algorithm::HS256,
            "HS384" => Algorithm::HS384,
            "HS512" => Algorithm::HS512,
            _ => Algorithm::HS256,
        };

        let mut validation = Validation::new(algo);
        validation.validate_exp = true;

        Self {
            decoding_key: DecodingKey::from_secret(secret.as_bytes()),
            validation,
        }
    }

    pub fn verify(&self, auth_header: &str) -> Result<Claims, AuthError> {
        let token = auth_header
            .strip_prefix("Bearer ")
            .ok_or(AuthError::InvalidFormat)?;

        let token_data = decode::<Claims>(token, &self.decoding_key, &self.validation)?;
        Ok(token_data.claims)
    }
}
```

#### 3.5 Main Proxy Service (`src/proxy.rs`)

```rust
use async_trait::async_trait;
use bytes::Bytes;
use http::{Response, StatusCode};
use pingora::prelude::*;
use pingora_proxy::{ProxyHttp, Session};
use std::sync::Arc;
use tracing::{info, warn, error};

use crate::auth::JwtVerifier;
use crate::cache::MediaCache;
use crate::config::Config;
use crate::gcs::GcsBackend;

pub struct MediaEdgeProxy {
    config: Arc<Config>,
    cache: Arc<MediaCache>,
    gcs: Arc<GcsBackend>,
    jwt: Arc<JwtVerifier>,
}

impl MediaEdgeProxy {
    pub async fn new(config: Config) -> anyhow::Result<Self> {
        let cache = Arc::new(MediaCache::new(
            config.cache_size_mb,
            config.cache_ttl_seconds,
        ));

        let gcs = Arc::new(GcsBackend::new(
            config.gcs_bucket.clone(),
            config.gcs_prefix.clone(),
        ).await?);

        let jwt = Arc::new(JwtVerifier::new(
            &config.jwt_secret,
            &config.jwt_algorithm,
        ));

        Ok(Self {
            config: Arc::new(config),
            cache,
            gcs,
            jwt,
        })
    }
}

#[async_trait]
impl ProxyHttp for MediaEdgeProxy {
    type CTX = ();

    fn new_ctx(&self) -> Self::CTX {}

    async fn request_filter(&self, session: &mut Session, _ctx: &mut Self::CTX) -> Result<bool> {
        let path = session.req_header().uri.path();

        // Health check bypass
        if path == "/health" || path == "/ready" {
            return Ok(false); // Continue to upstream_peer
        }

        // Check if content is premium (requires auth)
        // MVP: All /private/* paths require JWT
        if path.starts_with("/private/") {
            if let Some(auth_header) = session.req_header().headers.get("Authorization") {
                match self.jwt.verify(auth_header.to_str().unwrap_or("")) {
                    Ok(claims) => {
                        info!(user_id = %claims.sub, "JWT verified");
                    }
                    Err(e) => {
                        warn!(error = %e, "JWT verification failed");
                        let resp = Response::builder()
                            .status(StatusCode::UNAUTHORIZED)
                            .body(Bytes::from("Unauthorized"))
                            .unwrap();
                        session.respond(resp).await?;
                        return Ok(true); // Request handled
                    }
                }
            } else {
                let resp = Response::builder()
                    .status(StatusCode::UNAUTHORIZED)
                    .body(Bytes::from("Authorization required"))
                    .unwrap();
                session.respond(resp).await?;
                return Ok(true);
            }
        }

        // Try cache first
        let cache_key = path.to_string();
        if let Some((data, content_type)) = self.cache.get(&cache_key) {
            info!(path = %path, "Cache HIT");
            let resp = Response::builder()
                .status(StatusCode::OK)
                .header("Content-Type", content_type)
                .header("X-Cache", "HIT")
                .body(data)
                .unwrap();
            session.respond(resp).await?;
            return Ok(true);
        }

        // Cache miss - fetch from GCS
        info!(path = %path, "Cache MISS");
        match self.gcs.get_object(path.trim_start_matches('/')).await {
            Ok((data, content_type)) => {
                // Insert into cache
                self.cache.insert(cache_key, data.clone(), content_type.clone());

                let resp = Response::builder()
                    .status(StatusCode::OK)
                    .header("Content-Type", content_type)
                    .header("X-Cache", "MISS")
                    .body(data)
                    .unwrap();
                session.respond(resp).await?;
                Ok(true)
            }
            Err(e) => {
                error!(error = %e, path = %path, "GCS fetch failed");
                let resp = Response::builder()
                    .status(StatusCode::NOT_FOUND)
                    .body(Bytes::from("Not found"))
                    .unwrap();
                session.respond(resp).await?;
                Ok(true)
            }
        }
    }

    async fn upstream_peer(
        &self,
        _session: &mut Session,
        _ctx: &mut Self::CTX,
    ) -> Result<Box<HttpPeer>> {
        // Not used in this design - we handle everything in request_filter
        // But required by trait
        Ok(Box::new(HttpPeer::new(("127.0.0.1", 80), false, "")))
    }
}
```

#### 3.6 Main Entry Point (`src/main.rs`)

```rust
use anyhow::Result;
use pingora::prelude::*;
use prometheus::{Encoder, TextEncoder, Counter, register_counter};
use std::sync::Arc;
use tracing_subscriber::{layer::SubscriberExt, util::SubscriberInitExt};

mod auth;
mod cache;
mod config;
mod gcs;
mod proxy;

use config::Config;
use proxy::MediaEdgeProxy;

lazy_static::lazy_static! {
    static ref REQUESTS_TOTAL: Counter = register_counter!(
        "media_edge_requests_total",
        "Total number of requests"
    ).unwrap();

    static ref CACHE_HITS: Counter = register_counter!(
        "media_edge_cache_hits_total",
        "Total cache hits"
    ).unwrap();
}

fn main() -> Result<()> {
    // Initialize tracing (JSON format for GKE logging)
    tracing_subscriber::registry()
        .with(tracing_subscriber::fmt::layer().json())
        .with(tracing_subscriber::EnvFilter::from_default_env())
        .init();

    // Load config from environment
    let config = Config::from_env()?;

    // Create Pingora server
    let mut server = Server::new(None)?;
    server.bootstrap();

    // Create proxy service
    let proxy = tokio::runtime::Runtime::new()?
        .block_on(MediaEdgeProxy::new(config.clone()))?;

    // Create HTTP service
    let mut http_service = http_proxy_service(&server.configuration, proxy);
    http_service.add_tcp(&config.listen_addr);

    server.add_service(http_service);

    // Start metrics server on separate port
    let metrics_addr = config.metrics_addr.clone();
    std::thread::spawn(move || {
        let rt = tokio::runtime::Runtime::new().unwrap();
        rt.block_on(async {
            use hyper::{Body, Request, Response, Server as HyperServer};
            use hyper::service::{make_service_fn, service_fn};

            let make_svc = make_service_fn(|_| async {
                Ok::<_, hyper::Error>(service_fn(|_req: Request<Body>| async {
                    let encoder = TextEncoder::new();
                    let metric_families = prometheus::gather();
                    let mut buffer = vec![];
                    encoder.encode(&metric_families, &mut buffer).unwrap();
                    Ok::<_, hyper::Error>(Response::new(Body::from(buffer)))
                }))
            });

            let addr = metrics_addr.parse().unwrap();
            HyperServer::bind(&addr).serve(make_svc).await.unwrap();
        });
    });

    server.run_forever();
}
```

